int main() {
    // Create customers using shared_ptr for managed ownership
    std::shared_ptr<Customer> customerA = std::make_shared<Customer>(1, "Alice");
    std::shared_ptr<Customer> customerB = std::make_shared<Customer>(2, "Bob");

    // Create orders, passing shared_ptr which is converted to weak_ptr in Order
    Order order1(101, customerA);
    Order order2(102, customerB);

    std::cout << "--- Initial display ---" << std::endl;
    order1.displayOrderDetails();
    order2.displayOrderDetails();

    std::cout << "--- Resetting customerA shared_ptr (simulating customer deletion) ---" << std::endl;
    // When the last shared_ptr to customerA is reset, the Customer object is destroyed.
    customerA.reset(); 

    std::cout << "--- Display after customerA deletion ---" << std::endl;
    // order1's weak_ptr will now correctly report that the customer is no longer available
    order1.displayOrderDetails();
    order2.displayOrderDetails(); // customerB is still alive

    return 0;
}
